import { Outlet } from "react-router-dom";
import { useState, useEffect } from "react";

import data from "../InteristingTexts.json"

import TypingText from "../Components/TextComponents/TypingText";

function IdentificationPage() {
  const [item, setItem] = useState(null);

  useEffect(() => {
    const randomIndex = Math.floor(Math.random() * data.length);
    setItem(data[randomIndex]);
  }, []);
  console.log(item)

  if (!item || item.text === null) return <div>Загрузка...</div>;
  return (
    <div style={{display:"flex", width:"100%", height:"100%"}}>
      <div style={{
        width:"50%",
        height:"50%",
        display:"flex",
        justifyContent: "center",
      }}>
        <TypingText text={item.text}/>
      </div>
      <div style={{
      position: "absolute", 
      display:"flex",
      flexDirection: "column",
      right: "3%", 
      top: "50%", 
      transform: "translateY(-50%)",
      maxWidth: "720px",
      maxHeight: "745px",
      alignItems: "center",
      width: "100%",
      height: "100%",
      
      }}>
        <Outlet/>
      </div>
    </div>
  );
}

export default IdentificationPage;
